import{_ as n}from"./plugin-vue_export-helper-c27b6911.js";import{r as t,o as i,c as s,b as e,d as a,e as o,a as h}from"./app-99b09319.js";const d="/blog/assets/1711075173241-7dcfc4d6.png",c="/blog/assets/1711075844947-2024a0ea.png",l={},_={href:"https://juejin.cn/post/7161964571853815822",target:"_blank",rel:"noopener noreferrer"},p=h('<p><img src="'+d+'" alt="1711075173241"></p><p><img src="'+c+'" alt="1711075844947"></p><h2 id="_1-最左前缀匹配" tabindex="-1"><a class="header-anchor" href="#_1-最左前缀匹配" aria-hidden="true">#</a> 1.最左前缀匹配</h2><h2 id="_2-select" tabindex="-1"><a class="header-anchor" href="#_2-select" aria-hidden="true">#</a> 2.select *</h2><p>可以使用索引，除非where范围过大，但是不推荐使用select *，因为</p><ul><li>查找出来的字段可能没用，浪费网络资源</li><li>数据库变化而resultMap变化就会导致报错</li></ul><h2 id="_3-函数" tabindex="-1"><a class="header-anchor" href="#_3-函数" aria-hidden="true">#</a> 3. 函数</h2><p>函数本身也不会导致索引失效，但是如果改变了查询的值就会了，比如：</p><p>select a where length(a)=4</p><p>失效的原因是length(a)不是索引中的内容</p><h2 id="_4-计算操作" tabindex="-1"><a class="header-anchor" href="#_4-计算操作" aria-hidden="true">#</a> 4.计算操作</h2><p>计算操作也是同理</p><p>select a where a + 1 = 4</p><p>a + 1也不是索引的内容</p><h2 id="_5-like" tabindex="-1"><a class="header-anchor" href="#_5-like" aria-hidden="true">#</a> 5. like %</h2><p>左不走右走</p><h2 id="_6-in和not-in" tabindex="-1"><a class="header-anchor" href="#_6-in和not-in" aria-hidden="true">#</a> 6. in和not in</h2><p>这个不一定，如果in或者not in中数据大于30%，就不走索引了</p><h2 id="_7-order-by" tabindex="-1"><a class="header-anchor" href="#_7-order-by" aria-hidden="true">#</a> 7. order by</h2><p>order by 为了减少回表时间，直接走的全表扫描</p><h2 id="_8-or" tabindex="-1"><a class="header-anchor" href="#_8-or" aria-hidden="true">#</a> 8.or</h2><p>只有or左右都有索引才会走索引</p>',22);function u(f,b){const r=t("ExternalLinkIcon");return i(),s("div",null,[e("p",null,[a("总结于"),e("a",_,[a("https://juejin.cn/post/7161964571853815822"),o(r)])]),p])}const g=n(l,[["render",u],["__file","mysql_index_not_use.html.vue"]]);export{g as default};
